import { createHash } from "node:crypto";
import fs from "node:fs";
import path from "node:path";
import { environment } from "@raycast/api";
import type { PluginConfig } from "svgo";
import { OXVG_WASM_SHA256 } from "./vendor/oxvg-wasm-integrity";

// Vendored CJS build of @oxvg/wasm — generated by scripts/vendor-oxvg-wasm.mjs
// eslint-disable-next-line @typescript-eslint/no-require-imports
const oxvgWasm = require("./vendor/oxvg-wasm.cjs") as typeof import("./vendor/oxvg-wasm");

let initialized = false;

function ensureInitialized(): void {
  if (initialized) return;

  const wasmPath = path.join(environment.assetsPath, "oxvg_wasm_bg.wasm");
  const wasmBytes = fs.readFileSync(wasmPath);

  const actualHash = createHash("sha256").update(wasmBytes).digest("hex");
  if (actualHash !== OXVG_WASM_SHA256) {
    throw new Error(
      `OXVG WASM integrity check failed.\n` +
        `  Expected: ${OXVG_WASM_SHA256}\n` +
        `  Actual:   ${actualHash}\n` +
        `The WASM binary may be corrupted. Run \`npm run vendor:oxvg\` to regenerate it.`,
    );
  }

  oxvgWasm.initSync({ module: wasmBytes });
  initialized = true;
}

export function optimizeSvgWithOxvg(svg: string, plugins: PluginConfig[]): string {
  ensureInitialized();

  let jobs: ReturnType<typeof oxvgWasm.convertSvgoConfig> | undefined;
  try {
    const names = plugins.filter((p) => typeof p === "string") as string[];
    jobs = oxvgWasm.convertSvgoConfig(names);
  } catch {
    // Some SVGO plugin names have no OXVG equivalent — fall back to OXVG defaults.
    jobs = undefined;
  }

  return oxvgWasm.optimise(svg, jobs ?? null);
}

export function isOxvgAvailable(): boolean {
  try {
    ensureInitialized();
    return true;
  } catch {
    return false;
  }
}
